<template>
  <div class="my">
    <div class="my-box" :style="{backgroundImage: 'url(' + userInfo.userBg + ')'}">
      <div class="change-bg clearfix">
        <div class="fr bgc" v-if="isLogin">
          <div>更换背景</div>
          <van-uploader class="upload-box" :max-size="maxSize" :after-read="uploadFile" />
        </div>
      </div>
      <div class="user-info">
        <div v-if="isLogin">
          <div class="clearfix">
            <div class="my-img fl">
              <img class="auto-img" :src="userInfo.userImg" alt />
            </div>
            <div class="nickname fl">{{userInfo.nickName}}</div>
          </div>
          <div class="text">简介：{{userInfo.desc == '' ? '快留下你的脚印' : userInfo.desc}}</div>
        </div>
        <div class="login-text" v-else @click="togglePage('Login')">登录</div>
      </div>
    </div>

      <div class="manage-box" >
      <div class="vancell-box"  v-for="(item,index) in listsmanage" :key="index"  @click="togglePage(item.routeName)">
        <img class="img" :src="item.src" alt="">
      <van-cell :title="item.title" is-link />
      </div>
    </div>
  </div>
</template>

<script>
import "../../assets/css/my.less";
export default {
  data() {
    return {
      //上传文件1MB
      maxSize: 1 * 1024 * 1024,
     listsmanage:[
          {
            src:require("../../assets/images/zhanghao.png"),
            title: '账号管理',
            routeName: 'AccountManage'
          },
          {
            src:require("../../assets/images/localtion.png"),
            title: '地址管理',
            routeName: 'MyAddress'
          },
          {
            src:require("../../assets/images/mylike.png"),
            title: '我的收藏',
            routeName: 'MyLike'
          },
          {
            src:require("../../assets/images/secure.png"),
            title: '安全中心',
            routeName: 'Secure'
          }
        ],

      //用户信息
      userInfo: {},

      isLogin: false
    };
  },

  created() {
    this.getUserInfo();
    
    // if (localStorage.getItem('__TK')) {
    //   this.isLogin = true;
    // }
  },

  methods: {

    //跳转页面
    togglePage(name) {
      if (name === 'Login') {
        this.$router.push({name});
      } else {
        if (!this.isLogin) {
          this.$toast('请先登录');
        } else {
          this.$router.push({name});
        }
      }
      
    },

    //获取用户信息
    getUserInfo() {
      let tokenString = localStorage.getItem("__TK");
       if (!tokenString) {
          return;
        }
      this.$toast.loading({
        message: "加载中...",
        forbidClick: true,
        duration: 0,
        loadingType: 'spinner'
      });

      this.axios({
        method: "GET",
        url: "/findMy",
        params: {
          appkey: this.appkey,
          tokenString
        }
      })
        .then(result => {
          this.$toast.clear();
          

          if (result.data.code == "A001") {
             this.isLogin = true;
            this.userInfo = result.data.result[0];
          }
        })
        .catch(err => {
          this.$toast.clear();
          
        });
    },

    //获取上传文件的base64
    uploadFile(file) {
      

      //获取图片base64
      let serverBase64Img = file.content.replace(/^data:image\/[A-Za-z]+;base64,/, '');
      //获取图片类型
      let imgType = file.file.type.split('/')[1];

      let tokenString = localStorage.getItem("__TK");

      this.$toast.loading({
        message: "加载中...",
        forbidClick: true,
        duration: 0,
        loadingType: 'spinner'
      });

      this.axios({
        method: "POST",
        url: "/updateUserBg",
        data: {
          appkey: this.appkey,
          tokenString,
          imgType,
          serverBase64Img,
        }
      })
        .then(result => {
          this.$toast.clear();
          
          if (result.data.code == 'I001') {
            this.userInfo.userBg = result.data.userBg;
          } else {
            this.$toast(result.data.msg);
          }
        })
        .catch(err => {
          this.$toast.clear();
          
        });
    }
  }
};
</script>
